        villes: villeCanonical ? 1 : 0,
        emails: nbEmails,
        phones: nbPhones,
        urls: nbUrls,
        references: nbReferences,
      },
    },
  },
];"}, "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [-1968, -96], "id": "233f4734-414a-405d-9796-09d6bd041ae7", "name": "Code JS (anonymisation)", "disabled": true}, {"parameters": {"method": "POST", "url": "http://127.0.0.1:11434/api/generate", "sendBody": true, "specifyBody": "json", "jsonBody": "={{ (function() {
  const texte = $json.texte_anonymise || '';
