];"}, "id": "dc32aa6b-696a-4fa1-ab2a-a0eb6e50dca6", "name": "Code JS (fusion Ollama)", "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [-1968, 352], "disabled": true}, {"parameters": {"method": "POST", "url": "https://api.groq.com/openai/v1/chat/completions", "authentication": "genericCredentialType", "genericAuthType": "httpHeaderAuth", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "Authorization", "value": "=Bearer {{$credentials.groqApiKey}}"}]}, "sendBody": true, "specifyBody": "json", "jsonBody": "={{ (function() {
